class Solution {
    public int[] solution(int m, int n, int[][] picture) {
        boolean[][] visited = new boolean[m][n];
        int count = 0;
        int max = 0;
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (picture[i][j] != 0 && !visited[i][j]) {
                    count++;
                    max = Math.max(max, dfs(picture, visited, i, j));
                }
            }
        }
        return new int[]{count, max};
    }

    int dfs(int[][] picture, boolean[][] visited, int r, int c) {
        visited[r][c] = true;
        int size = 1;
        int[][] d = {{1,0},{-1,0},{0,1},{0,-1}};
        for (int[] dir : d) {
            int nr = r + dir[0], nc = c + dir[1];
            if (nr >= 0 && nr < picture.length && nc >= 0 && nc < picture[0].length
                    && !visited[nr][nc] && picture[nr][nc] == picture[r][c]) {
                size += dfs(picture, visited, nr, nc);
            }
        }
        return size;
    }
}
